use std::sync::{Arc, Mutex, atomic::{AtomicI32, Ordering}};
use std::thread;
use std::collections::HashMap;

#[derive(Debug)]
struct InventoryItem {
    stock: AtomicI32,
    id: i32,
}

#[derive(Debug)]
pub struct InventoryManager {
    items: Mutex<HashMap<i32, Arc<InventoryItem>>>,
}

impl InventoryManager {
    pub fn new() -> Self {
        InventoryManager {
            items: Mutex::new(HashMap::new()),
        }
    }

    pub fn add_item(&self, id: i32, initial_stock: i32) {
        let item = Arc::new(InventoryItem {
            stock: AtomicI32::new(initial_stock),
            id,
        });
        self.items.lock().unwrap().insert(id, item);
    }

    pub fn try_decrement_stock(&self, item_id: i32, quantity: i32) -> Result<bool, String> {
        let items = self.items.lock().unwrap();
        let item = items.get(&item_id).ok_or("Item not found")?;
        
        let current_stock = item.stock.load(Ordering::Acquire);
        
        if current_stock < quantity {
            return Ok(false);
        }
        
        let new_stock = current_stock - quantity;
        match item.stock.compare_exchange(
            current_stock,
            new_stock,
            Ordering::Acquire,
            Ordering::Acquire,
        ) {
            Ok(_) => Ok(true),
            Err(_) => Ok(false),
        }
    }

    pub fn get_stock(&self, item_id: i32) -> Result<i32, String> {
        let items = self.items.lock().unwrap();
        let item = items.get(&item_id).ok_or("Item not found")?;
        Ok(item.stock.load(Ordering::Acquire))
    }
}

pub fn concurrent_inventory_test() {
    let inventory = Arc::new(InventoryManager::new());
    inventory.add_item(1, 100);
    
    let mut handles = vec![];
    
    for _ in 0..10 {
        let inv = Arc::clone(&inventory);
        let handle = thread::spawn(move || {
            for _ in 0..5 {
                let result = inv.try_decrement_stock(1, 1);
                if let Ok(false) = result {
                    println!("Failed to decrement stock");
                }
            }
        });
        handles.push(handle);
    }
    
    for handle in handles {
        handle.join().unwrap();
    }
    
    println!("Final stock: {}", inventory.get_stock(1).unwrap());
}